package org.finos.legend.engine.deephaven.app.generated;

import io.deephaven.appmode.ApplicationState;
import io.deephaven.engine.context.ExecutionContext;
import io.deephaven.engine.liveness.LivenessScope;
import io.deephaven.engine.liveness.LivenessScopeStack;
import io.deephaven.engine.table.ColumnDefinition;
import io.deephaven.engine.table.Table;
import io.deephaven.engine.table.TableDefinition;
import io.deephaven.engine.table.impl.util.DynamicTableWriter;
import io.deephaven.engine.updategraph.UpdateGraph;

public class StocktradesappApp implements ApplicationState.Factory {

    @Override
    public ApplicationState create(ApplicationState.Listener listener) {
        ApplicationState state = new ApplicationState(listener, "stocktradesapp", "StockTradesApp");

        LivenessScope scope = new LivenessScope();
        LivenessScopeStack.push(scope);
        try {
            TableDefinition definition = TableDefinition.of(
                ColumnDefinition.ofInt("TradeID"),
ColumnDefinition.ofString("StockSymbol"),
ColumnDefinition.ofFloat("Price"),
ColumnDefinition.ofInt("Quantity"),
ColumnDefinition.ofString("City"),
ColumnDefinition.ofBoolean("IsBuy")
            );
            DynamicTableWriter writer = new DynamicTableWriter(definition);
            Table sourceTable = writer.getTable();

            UpdateGraph updateGraph = ExecutionContext.getContext().getUpdateGraph();
            Table result = updateGraph.exclusiveLock().computeLocked(
                () -> sourceTable.where(io.deephaven.api.filter.FilterComparison.eq(io.deephaven.api.ColumnName.of("City"),
                                                              io.deephaven.api.literal.Literal.of("New York")))
           .where(io.deephaven.api.filter.FilterComparison.eq(io.deephaven.api.ColumnName.of("IsBuy"),
                                                              io.deephaven.api.literal.Literal.of(true)))
           .select("StockSymbol")
            );

            state.setField("stockTrades", sourceTable);
            state.setField("result", result);
            state.setField("writer", writer);
        } finally {
            LivenessScopeStack.pop(scope);
        }
        return state;
    }
}
